import React from 'react'
import styled from 'styled-components'

const Form = styled.form `
position:fixed;
display:flex;
width:30vw;
height:80vh;
border-radius:5px;
background-color:white;
margin:auto;
top:0;
bottom:0;
left:0;
right:0;
z-index:2;
flex-direction:column;
justify-content:center;
align-items:center;
padding:30px 60px;
`

const Wrapper = styled.div ``


export default function Footer () {
	return (
		<Form>
			<Wrapper>
				<SignIn></SignIn>
				<Register></Register>
			</Wrapper>
			<Username></Username>
			<Email></Email>
			<Password></Password>
			<SignIn></SignIn>
			<OR></OR>
			<GoogleSignIn></GoogleSignIn>
			<FaceBookSignIn></FaceBookSignIn>
		</Form>
	)
}
